import os
import re

endpoint_dir = "api/v1/endpoints"
results = {}

for filename in sorted\(os.listdir\(endpoint_dir\)\):
    if not filename.endswith\('.py'\):
        continue

    filepath = os.path.join\(endpoint_dir, filename\)
    with open\(filepath, 'r'\) as f:
        lines = f.readlines\(\)

    file_issues = []

    # Check for commented code blocks \(3+ consecutive comment lines\)
    in_comment_block = 0
    comment_start = 0
    for i, line in enumerate\(lines\):
        stripped = line.strip\(\)
        if stripped.startswith\('#'\) and not stripped.startswith\('# ✅'\) and not stripped.startswith\('# CONFIGURAÇÃO'\):
            if in_comment_block == 0:
                comment_start = i + 1
            in_comment_block += 1
        else:
            if in_comment_block >= 3:
                file_issues.append\(\(comment_start, f"Large comment block \({in_comment_block} lines\)", "MEDIUM"\)\)
            in_comment_block = 0

    # Check for large commented code blocks
    in_block_comment = False
    block_start = 0
    for i, line in enumerate\(lines\):
        if '"""' in line or "'''" in line:
            in_block_comment = not in_block_comment
            if in_block_comment:
                block_start = i + 1

    if file_issues:
        results[filename] = file_issues

for filename, issues in results.items\(\):
    print\(f"\\n{filename}:"\)
    for line_num, issue, confidence in issues:
        print\(f"  Line {line_num}: {issue} [{confidence}]"\)

EOFPYTHON)

