import os
import re

# Get all model classes
with open\("models/models.py"\) as f:
    content = f.read\(\)

model_classes = re.findall\(r'^class\\s+\(\\w+\)\\s*\\\(', content, re.MULTILINE\)

# Check which are used in endpoints and main.py
used_models = set\(\)

for filename in os.listdir\("api/v1/endpoints"\):
    if filename.endswith\('.py'\):
        with open\(f"api/v1/endpoints/{filename}"\) as f:
            endpoint_content = f.read\(\)
        for model in model_classes:
            if model in endpoint_content:
                used_models.add\(model\)

# Check main.py
with open\("main.py"\) as f:
    main_content = f.read\(\)
for model in model_classes:
    if model in main_content:
        used_models.add\(model\)

# Enums are typically always used implicitly
enums = ['UserRole', 'InventoryStatus', 'CountingStatus', 'AssignmentStatus', 'CycleAuditActionEnum']

unused_models = []
for model in model_classes:
    if model not in used_models and model not in enums:
        # Double check by looking for string references
        found = False
        for root, dirs, files in os.walk\("."\):
            if root.startswith\("./.git"\) or "/__pycache__" in root:
                continue
            for file in files:
                if file.endswith\('.py'\):
                    with open\(os.path.join\(root, file\)\) as f:
                        if model in f.read\(\):
                            found = True
                            break
            if found:
                break

        if not found:
            unused_models.append\(model\)

print\("Potentially unused models:"\)
for model in sorted\(unused_models\):
    print\(f"  {model}"\)

print\(f"\\nTotal models: {len\(model_classes\)}"\)
print\(f"Used models: {len\(used_models\)}"\)
print\(f"Unused models: {len\(unused_models\)}"\)

EOFPYTHON)

